def GetLSProData(page_data,Cookie_Jar,m,url = ''):
    from resources.lib.modules import client,control
    import re,requests
    if not control.infoLabel('Container.PluginName') == 'plugin.video.thecrew': return
    urls = [
        'https://roxiestreams.su/mlb',
        'https://roxiestreams.info/mlb'
    ]
    page_data = ''
    for u in urls:
        try:
            page_data = requests.get(u, timeout=3).text
            if page_data and '<a href=' in page_data:
                break
        except:
            continue
    r = re.findall('(?s)<a href="([^"]*)">\\s*([^<]*)\\n.*?<td>\\s*([^<]*)\\n', page_data)
    return r
